var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"후우…… 이제 이걸로 마지막 스테이지만 남았나?","JPN":"ふう……もうこれで残ったのは最後のステージだけか？","ENG":"Phew... I guess I have only one stage left.","TWN":"呼呼……只剩下最後一關吧？"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그래, 떠올랐어.","JPN":"そうだ、思い出した。","ENG":"Yes, I remembered.","TWN":"沒錯，我想起來了。"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"이 캐릭터…… 그리고 이 목소리……. 어딘가 낯이 익다고 생각했는데……","JPN":"このキャラ……そして、この声……どこかで見聞きしたことがあるような気がすると思ったけど……","ENG":"This character... this voice... I thought it was somewhat familiar...","TWN":"這個角色……還有這個聲音……總覺得很熟悉……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그럴 수밖에 없지. 이건 내가 그린 <color=#ffd34c>미리네</color>니까.","JPN":"それもそのはずだ。これは私が描いた<color=#ffd34c>マリ</color>なのだから。","ENG":"Of course it is. This is <color=#ffd34c>Mi Rinae</color>, my own creation.","TWN":"廢話！這是我畫的<color=#ffd34c>宓璃奈</color>嘛！"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그리고 이 게임.","JPN":"そしてこのゲーム。","ENG":"And this game.","TWN":"還有這個遊戲，"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"<color=#ffd34c>카운터즈 사가</color>는…… 그 시절 모두가 함께 만든 게임이었다…….","JPN":"<color=#ffd34c>カウンターズ・サーガ</color>は……あの時、みんなで作ったゲームだった……","ENG":"<color=#ffd34c>Counters Saga</color>... is the game we made together.","TWN":"<color=#ffd34c>制裁者傳奇</color>……是那時候大家一起製作的遊戲……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그래, 거기까지는 알겠어.","JPN":"そう、そこまではわかる。","ENG":"Yeah. I remember now.","TWN":"沒錯，到這邊為止都沒錯，"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"하지만 나는 어째서 누나들을 잊게 된 거지?","JPN":"だが、私はどうしてみんなを忘れてしまったんだろう？","ENG":"But how did I come to forget everyone?","TWN":"但我為什麼會忘記姊姊她們呢？"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그 날, 코미페에서 무슨 일이 일어난 거야?","JPN":"あの日、コミフェでいったい何があったんだ？","ENG":"What really happened at Comic Festival?","TWN":"那天，在動漫展到底發生什麼事？"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"……잠깐.","JPN":"……待てよ。","ENG":"...Wait.","TWN":"……等等。"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그러고보니…… 선생님이라는 사람은 대체 누구지?","JPN":"そういえば……先生っていったい誰だったんだろう？","ENG":"Come to think of it... Who was that guy we called \\"Teacher\\"?","TWN":"這麼說來……那個叫老師的人究竟是誰？"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"어째선지…… 선생님 얼굴만큼은 떠오르지 않아…….","JPN":"どうしてか……先生の顔だけは思い出せない……","ENG":"Somehow... I can’t remember what he looked like...","TWN":"為什麼……我偏偏就是想不起老師的臉……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"선생님은…… 그때 분명히……","JPN":"先生は……あの時、確かに……","ENG":"Teacher... I’m sure he was...","TWN":"老師……那時候明明就……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군, 미래라는 건 아무도 알 수 없습니다.","JPN":"ダンボール君、未来というのは誰にもわからないものなんだ。","ENG":"No one knows what the future holds, Box.","TWN":"紙箱小朋友，未來的事誰也不知道。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 오히려 알 수 없기에 인간은 지금 이 순간에 충실해야 하죠.","JPN":"いや、むしろわからないからこそ、人間は今この瞬間を精一杯生きないといけないんだ。","ENG":"Which is why we need to focus on the present.","TWN":"應該是說，正是因為不知道，人們才更應該活在當下。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"때론 부질없어 보이는 작은 노력일지라도……","JPN":"今は無駄に見える小さな努力であっても……","ENG":"What might look like a useless act now...","TWN":"或許現在是看似毫無意義的努力……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 싹이 되어서 먼 미래의 어떤 결과를 바꿔 놓을 수도 있으니까요.","JPN":"それが芽生えて、遠い未来のある結果を変えることもあるからね。","ENG":"...Might grow into something powerful enough to change fate.","TWN":"但未來都有可能會萌芽長成某種結果。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건…… 이 세상 그 누구보다도 제가 가장 잘 알고 있습니다.","JPN":"それは……この世の誰よりも、私が一番よくわかっている。","ENG":"Trust me... I know more than anyone else in this world.","TWN":"這一點……我比世界上任何一個人都還要清楚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그래, 그땐 그게 무슨 말인지 몰랐지만……","JPN":"そうだ、あの時はそれがどんな意味なのかわからなかったけれど……","ENG":"Back then, I didn’t understand what he meant...","TWN":"那時候，我根本聽不懂老師在說什麼……"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"왠지 지금이라면…… 이해할 수 있을 것 같아.","JPN":"なぜか今なら……理解できそうな気がする。","ENG":"But now... I think I know.","TWN":"可是現在……不知道為什麼，好像可以理解。"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"좋아. 마지막까지 계속해보자. 그럼 분명 뭔가 떠올릴 수 있을 거야.","JPN":"よし。最後まで続けてみよう。そうすればきっと何か思い出せるはずだ。","ENG":"Okay. I’ll keep playing. Then I’ll be able to remember something else.","TWN":"好，繼續打到破關為止吧，那我應該會想起什麼吧？"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그동안 잊고 있었던 기억을……!","JPN":"今まで忘れていた記憶を……！","ENG":"The memories I have long forgotten...!","TWN":"關於我失去的那段記憶……！"},"stage":{"bg":"GAMECIRCLE_03","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};